INSERT INTO `rrt_bulletin_board_comments` (`id`, `thread_id`, `user_id`, `parent_id`, `content`, `created_at`, `updated_at`) VALUES (83, 26, 1, NULL, '\"I\'m so excited for Ark\'s debut! I\'ve already pre-ordered my copy. Can\'t wait to hear their music!', '2024-07-30 20:04:08', NULL), (84, 26, 171, NULL, 'The teasers look amazing. These boys are going to take the industry by storm. Ark fighting!', '2024-07-30 20:04:18', NULL), (85, 26, 170, NULL, 'I\'ve been waiting for this day since they were announced. Finally, we get to hear their talent. Let\'s support them', '2024-07-30 20:05:09', NULL), (87, 26, 170, 83, 'Me too! I\'ve been following them since their trainee days. The anticipation is killing me!', '2024-07-30 20:07:16', NULL), (88, 26, 1, 87, 'Tks', '2024-07-30 20:07:36', NULL), (89, 26, 1, NULL, 'I\'m counting down the days to their debut showcase. This is going to be legendary!', '2024-07-30 20:08:09', NULL), (90, 32, 196, NULL, 'liked', '2024-08-22 00:38:40', NULL), (91, 32, 196, 90, 'Oke', '2024-08-22 00:40:09', NULL), (92, 32, 196, NULL, 'Hello', '2024-08-22 00:40:21', NULL);
COMMIT;

