-- ----------------------------
-- Table structure for rrt_bulletin_board_translations
-- ----------------------------
DROP TABLE IF EXISTS `rrt_bulletin_board_translations`;
CREATE TABLE `rrt_bulletin_board_translations`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `bulletin_board_id` int NOT NULL,
  `language` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `meta_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `meta_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `meta_keyword` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `unique_translation`(`bulletin_board_id` ASC, `language` ASC) USING BTREE,
  CONSTRAINT `rrt_bulletin_board_translations_ibfk_1` FOREIGN KEY (`bulletin_board_id`) REFERENCES `rrt_bulletin_boards` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

-- ----------------------------
-- Records of rrt_bulletin_board_translations
-- ----------------------------
BEGIN;
INSERT INTO `rrt_bulletin_board_translations` (`id`, `bulletin_board_id`, `language`, `name`, `content`, `description`, `meta_title`, `meta_description`, `meta_keyword`, `created_at`, `updated_at`) VALUES (2, 53, 'kr', 'K팝 여왕 제시가 돌아왔다 123', '<p>가수 제시가 팬 폭행 논란에 대한 혐의가 무혐의로 풀린 지 불과 3개월 만에 필리핀 마닐라로의 기대를 모았던 복귀를 공식적으로 알렸습니다. 제시는 24일 소셜 미디어에 \"마닐라, 에너지에 감사합니다\"라는 글을 올리고 최근 콘서트의 순간을 담은 여러 장의 사진과 영상을 게재하며 감사를 표했습니다. 필리핀에서 열린 그녀의 최근 콘서트는 엄청난 성공을 거두며 열광적인 군중을 모았고 글로벌 퍼포머로서의 그녀의 지위를 더욱 공고히 했습니다. 팬들, 특히 그녀의 헌신적인 팬 클럽 \"제비즈\"는 그녀의 복귀를 간절히 기다렸고, 그녀는 강력하고 전기적인 무대 매너로 실망시키지 않았습니다. 공개된 사진에서 제시는 눈에 띄는 버건디 크롭 탑과 하네스 스타일 벨트, 검은색 가죽 허벅지 높이 부츠를 신으며 그녀만의 카리스마를 발산했습니다. 날카로운 컷아웃 디테일이 특징인 대담한 무대 의상은 그녀의 자신감과 거침없는 스타일을 완벽하게 보여주었습니다. 올해 초에 논란에 직면했음에도 불구하고 제시는 결국 무죄 판결을 받았고, 그녀는 음악과 공연에 전적으로 집중할 수 있었습니다. 마닐라로의 그녀의 승리의 귀환은 그녀의 커리어에 새로운 장을 알리는 것으로, 그녀는 여전히 그녀의 원초적인 에너지와 두려움 없는 예술성으로 전 세계 청중을 사로잡고 있습니다. 123</p>', NULL, NULL, NULL, NULL, '2025-04-03 19:03:18', '2025-04-10 22:42:57'), (3, 58, 'kr', NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 06:51:31', '2025-12-11 06:51:31'), (4, 59, 'kr', NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 11:05:55', '2025-12-11 11:05:55'), (5, 61, 'kr', NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 11:09:18', '2025-12-11 11:09:18'), (6, 63, 'kr', NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 11:15:27', '2025-12-11 11:15:27'), (7, 64, 'kr', NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 11:16:31', '2025-12-11 11:16:31'), (8, 65, 'kr', NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 11:18:49', '2025-12-11 11:18:49'), (9, 66, 'kr', NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 11:24:08', '2025-12-11 11:24:08'), (10, 67, 'kr', NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 11:25:42', '2025-12-11 11:25:42');
COMMIT;

-- ----------------------------
-- Table structure for rrt_bulletin_boards
-- ----------------------------
DROP TABLE IF EXISTS `rrt_bulletin_boards`;
CREATE TABLE `rrt_bulletin_boards`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `language` varchar(2) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT 'en',
  `name` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `code` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `desc` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `content` longtext CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `category_id` int NULL DEFAULT NULL,
  `type` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `admin_id` int NULL DEFAULT NULL,
  `thumbnail` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `view` int NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `link` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 68 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

-- ----------------------------
-- Records of rrt_bulletin_boards
-- ----------------------------
BEGIN;
INSERT INTO `rrt_bulletin_boards` (`id`, `language`, `name`, `code`, `desc`, `content`, `category_id`, `type`, `user_id`, `admin_id`, `thumbnail`, `view`, `created_at`, `updated_at`, `deleted_at`, `link`) VALUES (23, 'en', 'EXO’s D.O. Talks Full-Group Comeback Plans During SM Entertainment\'s 30th Anniversary Event', '579061', 'EXO’s D.O. Talks Full-Group Comeback Plans During SM Entertainment\'s 30th Anniversary Event', '<p>On January 22, actor and EXO member D.O. (Do Kyung Soo) shared exciting news about the group&rsquo;s upcoming plans for full-group activities, speaking during SM Entertainment&rsquo;s 30th-anniversary concert.</p>\r\n\r\n<p>When asked about the prospect of EXO reuniting as a complete group, D.O. was clear and optimistic, saying, &ldquo;Of course, you&rsquo;ll see us as a full group.&rdquo; He further assured fans, stating, &ldquo;We&rsquo;re beginning preparations now. There&rsquo;s no need to worry. You&rsquo;ll definitely see EXO as a full group soon.&rdquo;</p>\r\n\r\n<p>While confirming that the preparations are already underway, D.O. tempered expectations by noting that a full-group return might not occur within 2025. &ldquo;Even though it might not happen this year, it won&rsquo;t be too long,&rdquo; he explained. &ldquo;We&rsquo;ve coordinated everyone&rsquo;s schedules and started the preparations.&rdquo;</p>\r\n\r\n<p>Responding to questions about EXO&rsquo;s continued strength as a unit, D.O. expressed confidence, affirming, &ldquo;Of course,&rdquo; and addressed concerns about the members being in different agencies. &ldquo;Even though we are with different agencies now, all matters related to EXO are still managed by SM Entertainment. Nothing has changed,&rdquo; he emphasized, offering reassurance to fans about the group&#39;s unity.</p>\r\n\r\n<p>D.O.&rsquo;s comments have sparked excitement among EXO&rsquo;s dedicated fanbase, who can now look forward to the group&#39;s full return in the near future.</p>', 6, NULL, 1, 60, '캡처-l5k7jGqJlm.jpg', 425, '2025-01-22 05:09:39', NULL, '2025-12-11 11:04:26', NULL), (24, 'en', 'SEVENTEEN and Pharrell Williams Collaborate on ‘Bad Influence’ for Louis Vuitton\'s Paris Fashion Week Show', '366755', 'SEVENTEEN and Pharrell Williams Collaborate on ‘Bad Influence’ for Louis Vuitton\'s Paris Fashion Week Show', '<p>SEVENTEEN members S.Coups, Hoshi, Wonwoo, Woozi, The8, DK, Seungkwan, Vernon, and Dino have teamed up with renowned artist Pharrell Williams for a new track, <em>Bad Influence</em>, which was unveiled on January 21 during the Louis Vuitton Men&rsquo;s Fall-Winter 2025 show at Paris Fashion Week.</p>\r\n\r\n<p>The song, composed by Pharrell Williams&mdash;who also serves as the Creative Director for Louis Vuitton Men&rsquo;s&mdash;was created specifically for the high-profile event. SEVENTEEN&rsquo;s rendition of <em>Bad Influence</em> offered a fresh, dynamic energy to the Paris runway, captivating the global fashion community.</p>\r\n\r\n<p>The members of SEVENTEEN expressed their excitement over the collaboration, sharing, &ldquo;It&rsquo;s an honor to work with Pharrell Williams, an artist we&rsquo;ve always admired. Creating a song that showcases a new side of SEVENTEEN was an enjoyable experience. We hope our music resonates with even more listeners around the world.&rdquo;</p>\r\n\r\n<p>Pharrell Williams, a 13-time Grammy Award-winning producer and artist, is widely celebrated for hits like <em>Happy</em>. SEVENTEEN, known for their international appeal, has previously collaborated with major global artists including DJ Khaled, Shift K3Y, Marshmello, New Kids on the Block, Anne-Marie, Charli XCX, and Pink Sweat$, reinforcing their presence in the global music landscape.</p>\r\n\r\n<p>As part of their 10th-anniversary celebrations, SEVENTEEN is continuing their worldwide activities. After their successful performances on January 18-19 at the Bulacan Philippine Sports Stadium, the group will take their <em>SEVENTEEN [RIGHT HERE] WORLD TOUR IN ASIA</em> to audiences in Singapore (January 25-26), Jakarta (February 8-9), and Bangkok (February 15-16). Additionally, SEVENTEEN is set to make history in April as the first K-pop group to perform at Tecate Pa&rsquo;l Norte 2025, known as the &quot;Coachella of Mexico.</p>', 6, NULL, 1, 60, '캡처-m1r1eP0igK.jpg', 595, '2025-01-22 05:11:39', NULL, '2025-12-11 11:03:04', NULL), (25, 'en', 'Jennie of Black Pink Announces Debut Solo Album \'Ruby\' Set for March Release', '369217', 'Jennie of Black Pink Announces Debut Solo Album \'Ruby\' Set for March Release', '<p>Jennie will release her highly anticipated debut solo album, <em>Ruby</em>, on March 7th, according to ODDATELIER Entertainment&rsquo;s announcement on January 22nd KST. The album will feature 15 tracks, including her previously released October 2024 single, <em>Mantra</em>, further showcasing her expansive musical range.</p>\r\n\r\n<p><em>Ruby</em> will also include collaborations with an impressive roster of international artists, including Childish Gambino, Doechii, Dominic Fike, Dua Lipa, FKJ, and Kali Uchis. This star-studded lineup promises an album that is poised to captivate audiences globally.</p>\r\n\r\n<p>Jennie has already made a significant impact with <em>Mantra</em>, which topped iTunes&rsquo; Top Songs charts in 47 countries and regions, including the United States, Brazil, Singapore, the Philippines, and Mexico. The track also made its mark on the Billboard Hot 100, charting for two consecutive weeks, and became the first K-pop female soloist to reach number one on the U.S. iTunes Top Songs chart.</p>\r\n\r\n<p>With the release of <em>Ruby</em>, fans worldwide are eager to see how Jennie will continue to define her unique musical identity and further solidify her position as a global artist.</p>\r\n\r\n<p>In addition to her album release, Jennie has been confirmed as a solo performer at the prestigious Coachella Valley Music and Arts Festival, scheduled for April 13th and 20th (local time) in Indio, California. This announcement has fueled growing anticipation for her upcoming performances, heightening expectations for her global presence.</p>', 6, NULL, 1, 60, '캡처-Rzo9Nq3x9R.jpg', 544, '2025-01-22 05:16:20', NULL, '2025-12-11 11:03:02', NULL), (26, 'en', 'GOT7 Makes a Strong Comeback with \'WINTER HEPTAGON,\' Dominating iTunes Charts', '121818', 'GOT7 Makes a Strong Comeback with \'WINTER HEPTAGON,\' Dominating iTunes Charts', '<p>GOT7 has made a powerful return to the music scene with their highly-anticipated mini-album <em>WINTER HEPTAGON</em>, quickly climbing to the top of iTunes charts globally.</p>\r\n\r\n<p>Upon its release on January 20, <em>WINTER HEPTAGON</em> immediately soared to the No. 1 spot on both the worldwide iTunes album chart and the European iTunes album chart, marking a triumphant comeback for the group.</p>\r\n\r\n<p>The album continued to dominate, reaching No. 1 on iTunes&rsquo; <em>Top Album</em> charts in 40 countries, including Australia, Chile, Colombia, France, Hong Kong, Indonesia, Macau, the Netherlands, the Philippines, Singapore, and more.</p>\r\n\r\n<p>In addition, the title track <em>Python</em> has made waves, securing the No. 1 position on iTunes&rsquo; <em>Top Song</em> charts in over 20 regions.</p>\r\n\r\n<p>GOT7&rsquo;s impressive chart performance with <em>WINTER HEPTAGON</em> underscores the group&rsquo;s enduring popularity and global appeal.<br />\r\n<br />\r\nCongratulations to GOT7 on their remarkable success!</p>', 6, NULL, 171, 60, '캡처-HJilW22ZIH.jpg', 751, '2025-01-22 05:19:36', NULL, '2025-12-11 11:03:01', NULL), (27, 'en', '\"FNC Music\'s Concentration\" FNC Kingdom, Held in December on Japan... Bands, Actors, and Dance Groups All Gathered', '603694', 'FNC artists with diverse talents such as bands, actors, and dance groups will showcase various performances and collaboration stages on \'FNC Kingdom\'. The attention of global K-pop fans is focused on \'FNC Kingdom\', which is expected to be a high-quality stage filled with overwhelming skills and know-how.', '<div>[SPOTV News=Reporter Won-gyeom Kim] FNC Entertainment (hereafter FNC) will be holding \'FNC Kingdom\' where they will become one through FNC\'s signature music.</div><div><br></div><div>FNC will be holding \'2024 FNC Kingdom - Sing Sing Sing -\' (hereafter \'FNC Kingdom\') on December 14th and 15th at the Makuhari Messe International Exhibition Center in Chiba, Japan. \'FNC Kingdom\', which began in 2013, is a large-scale family concert representing FNC.</div><div><br></div><div>The title of this concert, \'SING SING SING\', contains the meaning of FNC artists and fans becoming one through song. The released image raises expectations as it features the names of the artists against a backdrop of splendid fireworks above the kingdom representing \'FNC Kingdom\'.</div><div><br></div><div>All of FNC\'s artists will gather at \'FNC Kingdom\'. The show will feature representative Korean bands FT Island and CNBLUE, as well as actor Jung Hae-in who is set to captivate both TV and screens with the upcoming tvN drama \'Mom\'s Friend Son\' and movie \'Veteran 2\', youth band N.Flying who are on the rise with their new song \'You Have a Place in My Heart\' in addition to their fan song \'Blue Moon\' chart-topping, SF9 who are busy continuing their activities in music, musicals, variety shows, and dramas with an announcement of a comeback in August, and actor Rowoon who is in the spotlight with his active activities such as acting and global fan meetings.</div><div><br></div><div>In addition, P1Harmony who are continuing their global popularity with a series of large-scale world tours including entering the Billboard main chart, band Hi-Fi Unicorn who are celebrating their first debut anniversary with the release of their first album \'Fantasia\' and announcing a live house tour, and Ampersand One who are garnering attention for their trendy yet friendly charm with their multinational members have also announced their appearance, raising expectations.</div>', 3, NULL, 1, NULL, '0000504833_001_20240731050613491-glH3CIZqzw.jpg', 75, '2024-07-30 20:13:40', NULL, '2025-01-22 05:11:51', NULL), (43, 'en', 'Kay', '623006', 'ROKHipHop 4 Life', '<p>ROKHipHop 4 Life</p>', 1, 'free', 279, NULL, NULL, 0, '2025-02-17 16:14:32', NULL, '2025-02-17 16:15:28', NULL), (44, 'en', 'asdf', '775321', 'sadf', '<p>asdf</p>', 1, 'free', 279, NULL, NULL, 6, '2025-02-19 07:01:25', NULL, '2025-02-26 10:17:48', NULL), (45, 'en', 'Yeji: From Audition Standout to Solo Flight with \"Air\"', '384957', 'Yeji: From Audition Standout to Solo Flight with \"Air\"', '<p>Hwang Yeji&#39;s trajectory within the K-Pop landscape has been marked by a consistent ascent. Her initial public exposure on SBS&#39;s &quot;The Fan&quot; in 2018, where she demonstrated exceptional talent amidst established industry peers, served as a compelling precursor to her formal debut. Subsequently, in February 2019, as a core member of ITZY, she rapidly garnered acclaim for her dynamic performance capabilities, nuanced stage presence, and robust vocal delivery.</p>\r\n\r\n<p>Over the ensuing six years, Yeji has contributed significantly to ITZY&#39;s discography, contributing to chart-topping releases such as &quot;LOCO,&quot; &quot;ICY,&quot; &quot;WANNABE,&quot; and &quot;Not Shy.&quot; These releases have solidified her reputation as a formidable performer within the genre. In 2023, the track &quot;Crown On My Head,&quot; featured on ITZY&#39;s album &quot;BORN TO BE,&quot; provided a strategic platform for Yeji to showcase her potential as a solo artist, demonstrating a refined artistic vision.</p>\r\n\r\n<p>The upcoming release of &quot;Air&quot; signifies a pivotal moment in Yeji&#39;s career arc. This project represents the culmination of her sustained professional development and signals her readiness to expand her artistic footprint. The anticipated release is positioned to capitalize on her established fanbase while attracting new demographics through a refined and mature aesthetic.</p>\r\n\r\n<p>Yeji&#39;s career exemplifies the strategic development of a contemporary K-Pop artist. Her progression from a promising talent on an audition program to a seasoned performer within a prominent group, and now a solo artist, demonstrates a clear understanding of brand building and audience engagement. The release of &quot;Air&quot; is a calculated move, leveraging her established brand equity to further diversify her artistic portfolio.</p>\r\n\r\n<p>&nbsp;</p>', 8, NULL, NULL, 60, 'Itzy 예지-qwaR9aTScv.png', 457, '2025-03-10 11:27:31', NULL, '2025-12-11 11:02:59', NULL), (46, 'en', 'Hoshi and Woozi\'s \"BEAM\": Illuminating Artistic Growth Through Focused Single Album', '497862', 'Hoshi and Woozi\'s \"BEAM\": Illuminating Artistic Growth Through Focused Single Album', '<p>The debut single album, &quot;BEAM,&quot; from Hoshi and Woozi, functions as a curated exploration of light as a symbolic representation of their artistic and personal development. This release chronicles their progression from their formative trainee years to their established position within the K-Pop landscape, framing their journey as a narrative of self-discovery and creative integrity. The album&#39;s thematic coherence, centered on the multifaceted concept of light, provides a unifying thread throughout the three tracks.</p>\r\n\r\n<p>The &quot;BEAM&quot; single album features a concise tracklist, comprising the lead single &quot;Same Age,&quot; the collaborative track &quot;PINOCCHIO&quot; (featuring So!YoON!), and &quot;STUPID IDIOT.&quot; A key aspect of this release is the demonstrable creative control exercised by both Hoshi and Woozi, evidenced by their significant contributions to the songwriting and composition processes. This active involvement underscores their artistic vision and commitment to the project. The focused nature of the single album, coupled with its strong thematic framework, positions &quot;BEAM&quot; as a deliberate artistic statement, highlighting the duo&#39;s evolution and creative agency.</p>', 9, NULL, NULL, 60, '호시 우지-wKqHTJZNAk.png', 676, '2025-03-17 06:59:49', NULL, '2025-12-11 11:02:57', NULL), (47, 'en', 'test', '840027', 'test', '<p>test</p>', 8, 'free', 1, NULL, NULL, 3, '2025-03-17 02:53:36', NULL, '2025-03-24 03:40:37', NULL), (48, 'en', 'test', '329273', 'test', '<p>test</p>', 8, 'free', 1, NULL, NULL, 4, '2025-03-17 02:56:50', NULL, '2025-03-24 03:40:35', NULL), (49, 'en', 'test', '288229', 'test', '<p>test</p>', 8, 'free', 1, 60, 'ai-image-T_o_m_t_b_c_tranh_s_-2025-03-06T10-09-52-654Z-T5DfVigDYa.png', 0, '2025-03-17 02:59:57', NULL, '2025-03-17 06:57:59', NULL), (50, 'en', 'test 123', '816469', 'test desc', '<p>test content</p>', 8, 'free', 1, NULL, NULL, 4, '2025-03-20 02:20:18', NULL, '2025-03-24 03:40:32', NULL), (51, 'en', 'Test', '706332', '15125', NULL, 1, 'free', 1, NULL, NULL, 2, '2025-03-21 19:12:04', NULL, '2025-03-24 03:40:30', 'https://1n2music.com/en/'), (52, 'en', 'test', '403592', 'test', NULL, 1, 'free', 1, NULL, NULL, 320, '2025-03-24 08:46:24', NULL, '2025-12-11 11:04:32', '#'), (53, 'en', 'K-Pop Queen Jessi is BACK after being cleared of allegations in the controversy!', '317248', 'K-Pop queen Jessi is BACK', '<p>Singer Jessi has officially signaled her highly anticipated return to Manila, Philippines, just three months after being cleared of allegations in the fan assault controversy.</p><p>On the 24th, Jessi took to her social media to express her gratitude, writing, \"Thank you for the energy, Manila,\" alongside several photos and videos capturing moments from her recent concert.</p><p>Her latest concert in the Philippines was a massive success, drawing an enthusiastic crowd and further solidifying her status as a global performer. Fans, especially her devoted fan club \"Jebbies,\" had eagerly awaited her return, and she did not disappoint with a powerful and electrifying stage presence.</p><p>In the released photos, Jessi exuded her signature charisma, donning a striking burgundy crop top paired with a harness-style belt and black leather thigh-high boots. The bold stage outfit, featuring edgy cut-out details, perfectly showcased her confidence and unapologetic style.</p><p>Despite facing controversy earlier in the year, Jessi was ultimately ruled innocent, allowing her to focus entirely on her music and performances. Her triumphant return to Manila marks a new chapter in her career, as she continues to captivate audiences worldwide with her raw energy and fearless artistry.</p>', 10, NULL, NULL, 60, 'jess-3C81cZ0HGX.jpg', 479, '2025-04-03 06:33:02', NULL, '2025-12-11 11:02:54', NULL), (54, 'en', 'Whats up', '187127', 'huh???', NULL, 1, 'free', 279, NULL, NULL, 293, '2025-04-04 09:03:19', NULL, '2025-12-11 11:04:30', NULL), (58, 'en', 'test', '997699', '125', '<p>125</p>', 10, NULL, NULL, 1, NULL, 0, '2025-12-11 06:51:31', NULL, '2025-12-11 06:51:45', NULL), (59, 'en', 'ASTRO’s MJ Set for Long-Awaited Solo Comeback', '928613', 'ASTRO’s MJ Set for Long-Awaited Solo Comeback', '<p>ASTRO member <strong>MJ</strong> is officially returning with a new solo project.<br>He teased his upcoming digital single <strong>“12시 25분 (CLOCK)”</strong>, scheduled for release on <strong>December 16 at 6 PM KST</strong>.</p><p>This marks MJ’s <strong>first solo comeback in roughly four years</strong>, creating anticipation among fans eager to see how his sound will evolve post-military service and group activities. The announcement has already sparked strong buzz across social media, signaling a warm welcome for his comeback.</p>', 10, NULL, NULL, 60, 'astro-Nes4QWjU2r.webp', 1, '2025-12-11 11:05:55', NULL, '2025-12-11 11:09:06', NULL), (60, 'en', 'ASTRO’s MJ Set for Long-Awaited Solo Comeback', '891671', 'ASTRO’s MJ Set for Long-Awaited Solo Comeback', '<p>ASTRO member <strong>MJ</strong> is officially returning with a new solo project.<br />\r\nHe teased his upcoming digital single <strong>&ldquo;12시 25분 (CLOCK)&rdquo;</strong>, scheduled for release on <strong>December 16 at 6 PM KST</strong>.</p>\r\n\r\n<p>This marks MJ&rsquo;s <strong>first solo comeback in roughly four years</strong>, creating anticipation among fans eager to see how his sound will evolve post-military service and group activities. The announcement has already sparked strong buzz across social media, signaling a warm welcome for his comeback.</p>', 10, 'free', NULL, 60, 'astro-WEk6d5eA9K.webp', 0, '2025-12-11 11:12:22', NULL, '2025-12-11 11:20:08', NULL), (61, 'en', '12', '733117', '1212', '<p>12</p>', 10, NULL, NULL, 1, NULL, 1, '2025-12-11 11:09:18', NULL, '2025-12-11 11:15:35', NULL), (62, 'en', 'Test', '200031', '<p>125</p>', NULL, 1, 'free', 1, NULL, NULL, 0, '2025-12-11 11:12:23', NULL, '2025-12-11 11:12:34', NULL), (63, 'en', 'ASTRO’s MJ Set for Long-Awaited Solo Comeback', '338345', 'ASTRO member MJ is officially returning with a new solo project.', '<p>ASTRO member <strong>MJ</strong> is officially returning with a new solo project.<br>He teased his upcoming digital single <strong>“12시 25분 (CLOCK)”</strong>, scheduled for release on <strong>December 16 at 6 PM KST</strong>.</p><p>This marks MJ’s <strong>first solo comeback in roughly four years</strong>, creating anticipation among fans eager to see how his sound will evolve post-military service and group activities. The announcement has already sparked strong buzz across social media, signaling a warm welcome for his comeback.</p>', 10, NULL, NULL, 60, 'astro-nDiwp1SZgc.webp', 292, '2025-12-11 11:15:27', NULL, NULL, NULL), (64, 'en', 'Hwa Sa Earns First Music Show Win for “Good Goodbye”', '210444', 'Hwa Sa Earns First Music Show Win for “Good Goodbye”', '<p>On the December 6th broadcast of <strong>“Show! Music Core,” Hwa Sa</strong> secured the trophy with her solo track <strong>“Good Goodbye.”</strong></p><p>Although the song was released over two months ago, its continued digital and performance momentum pushed it to finally clinch a music-show win. Her charismatic live stage and strong public response highlight Hwa Sa’s staying power as a solo performer, independent of her MAMAMOO activities.</p>', 10, NULL, NULL, 60, 'hwasa-1b9pbjlagU.webp', 268, '2025-12-11 11:16:31', NULL, NULL, NULL), (65, 'en', 'Hwa Sa Earns First Music Show Win for “Good Goodbye”', '713678', 'Hwa Sa Earns First Music Show Win for “Good Goodbye”', '<p>On the December 6th broadcast of <strong>“Show! Music Core,” Hwa Sa</strong> secured the trophy with her solo track <strong>“Good Goodbye.”</strong></p><p>Although the song was released over two months ago, its continued digital and performance momentum pushed it to finally clinch a music-show win. Her charismatic live stage and strong public response highlight Hwa Sa’s staying power as a solo performer, independent of her MAMAMOO activities.</p>', 10, NULL, NULL, 60, 'hwasa-8zgQ4tVF04.webp', 0, '2025-12-11 11:18:49', NULL, '2025-12-11 11:18:58', NULL), (66, 'en', 'LE SSERAFIM Gains International Critical Recognition', '973097', 'LE SSERAFIM Gains International Critical Recognition', '<p>Global music media continues to recognize K-pop’s influence, with <strong>LE SSERAFIM</strong> being the <strong>only K-pop act</strong> featured in <strong>Consequence’s “The 200 Best Songs of 2025.”</strong></p><p>Their track <strong>“Come Over”</strong> ranked at <strong>#90</strong>, an impressive feat considering it\'s not even a title track.<br>The song earned praise for its dreamy production, vocal layering, and unique sonic identity — showcasing the group’s artistic depth beyond mainstream hits.</p><p>This accomplishment strengthens LE SSERAFIM’s status not only as chart performers but as globally respected music creators.</p>', 10, NULL, NULL, 60, 'GROUP-PHOTO_C-e1741929704787-y4hsvbtLbn.webp', 259, '2025-12-11 11:24:08', NULL, NULL, NULL), (67, 'en', 'Spotify Reveals 2025’s Top K-Pop Artists & Songs', '930000', 'Spotify Reveals 2025’s Top K-Pop Artists & Songs', '<p>Spotify released its <strong>2025 Global K-Pop Streaming Rankings</strong>, revealing the growing global footprint of Korean music.</p><p>K-pop reached <strong>181 billion minutes of streaming worldwide</strong> this year, showing no slowdown in global demand.<br>Among the most streamed artists were:</p><ul><li><strong>BTS</strong></li><li><strong>Stray Kids</strong></li><li><strong>JENNIE</strong></li><li><strong>ROSÉ</strong></li><li><strong>HUNTR/X</strong></li><li><strong>TWICE</strong></li><li><strong>BLACKPINK</strong></li></ul><p>This year’s data reflects not only idol-group dominance but also the rise of <strong>soloists</strong> and <strong>OST-driven acts</strong>, indicating a diverse expansion of Korean music consumption across international listeners.</p>', 10, NULL, NULL, 60, 'G7TPdN8XcAAm7Ge-VqyurDxXOH.jpg', 279, '2025-12-11 11:25:42', NULL, NULL, NULL);
COMMIT;

-- ----------------------------
-- Table structure for rrt_comment_track
-- ----------------------------
DROP TABLE IF EXISTS `rrt_comment_track`;
CREATE TABLE `rrt_comment_track`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NULL DEFAULT NULL,
  `track_id` int NULL DEFAULT NULL,
  `parent_id` int NULL DEFAULT NULL,
  `content` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 79 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

-- ----------------------------
-- Records of rrt_comment_track
-- ----------------------------
