-- ----------------------------
-- Table structure for rrt_contract_settings
-- ----------------------------
DROP TABLE IF EXISTS `rrt_contract_settings`;
CREATE TABLE `rrt_contract_settings`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `contract_id` int NULL DEFAULT NULL,
  `category` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `status` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `enabled` int NULL DEFAULT 1,
  `description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `featureList` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `deliverables` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `isFeatured` int NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `cs_contract_id`(`contract_id` ASC) USING BTREE,
  INDEX `cs_user_id`(`user_id` ASC) USING BTREE,
  CONSTRAINT `cs_contract_id` FOREIGN KEY (`contract_id`) REFERENCES `rrt_contracts` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `cs_user_id` FOREIGN KEY (`user_id`) REFERENCES `rrt_users` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 10388 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

-- ----------------------------
-- Records of rrt_contract_settings
-- ----------------------------
BEGIN;
