-- Records of rrt_faqs
-- ----------------------------
BEGIN;
INSERT INTO `rrt_faqs` (`id`, `name`, `content`, `category_id`, `order_number`, `created_at`) VALUES (1, 'Do you give me information about who buys or downloads my music?', 'Yes, you can check the transaction history on the seller page.', 1, 0, '2023-10-03 16:23:45'), (2, 'Do I have to maintain my membership at all times?', 'No, you can change or cancel your membership at any time.', 1, 0, '2023-10-03 16:24:40'), (3, 'How do you get money from music sales?', '<p>When someone purchases music from 1N2Music, the customer is instructed to make the payment through the platform. After the transaction is completed, the sales will immediately appear in the seller&#39;s sales information, and if you request a withdrawal, you can receive cash deposit to your designated bank account. Minimum Withdrawl is $50 USD.</p>', 1, 0, '2025-03-27 14:46:35'), (4, 'Can I distribute my music world wide?', '<p>Of course, you can allow unlimited free downloads or unlimited streaming (playing) of music you make on any playform of your choice!</p>', 1, 0, '2025-02-26 10:16:50'), (6, '2152', '<p>125215</p>', NULL, 0, '2023-10-03 17:25:22'), (7, 'How to play music', '<p>Just click on play button</p>', NULL, 0, '2024-09-10 03:38:58');
COMMIT;

