-- ----------------------------
-- Table structure for rrt_log_order
-- ----------------------------
DROP TABLE IF EXISTS `rrt_log_order`;
CREATE TABLE `rrt_log_order`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `order_id` int NULL DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `fw_log_order_order_id`(`order_id` ASC) USING BTREE,
  CONSTRAINT `fw_log_order_order_id` FOREIGN KEY (`order_id`) REFERENCES `rrt_order` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 156 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

