  `stereo_mid_width` float NULL DEFAULT NULL,
  `stereo_high_width` float NULL DEFAULT NULL,
  `bass_preservation` tinyint(1) NULL DEFAULT NULL,
  `bit_depth` int NULL DEFAULT NULL,
  `ceiling` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `ceiling_mode` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `failure_reason` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
