-- ----------------------------
-- Table structure for rrt_music_distribution
-- ----------------------------
DROP TABLE IF EXISTS `rrt_music_distribution`;
CREATE TABLE `rrt_music_distribution`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `code` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `title_track` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `artist_name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `explicit_content` int NOT NULL DEFAULT 0,
  `producers` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `composers` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `lyricists` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `isrc_code` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `upc_code` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `label` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `publishing_information` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `distribution_information` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `keywords` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `sns_link` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `catalog_number` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `type` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `status` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT 'new',
  `genre_id` int NULL DEFAULT NULL,
  `subgenre_id` int NULL DEFAULT NULL,
  `shop_id` int NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `release_date` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `2nd_release_date` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `name` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `copyright` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `artist_id` int NULL DEFAULT NULL,
  `label_id` int NULL DEFAULT NULL,
  `thumbnail` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `fk_rrt_music_distribution_artist_id`(`artist_id` ASC) USING BTREE,
  INDEX `fk_rrt_music_distribution_shop_id`(`shop_id` ASC) USING BTREE,
  CONSTRAINT `fk_rrt_music_distribution_artist_id` FOREIGN KEY (`artist_id`) REFERENCES `rrt_music_distribution_artists` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `fk_rrt_music_distribution_shop_id` FOREIGN KEY (`shop_id`) REFERENCES `rrt_music_distribution_shops` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 148 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

