-- ----------------------------
-- Table structure for rrt_order
-- ----------------------------
DROP TABLE IF EXISTS `rrt_order`;
CREATE TABLE `rrt_order`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `code` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `status` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT 'order',
  `fullname` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `country_code` varbinary(255) NULL DEFAULT NULL,
  `phone` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `email` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `address` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `total` float NULL DEFAULT 0,
  `total_payment` float NULL DEFAULT 0,
  `is_refund` int NULL DEFAULT 0,
  `total_refund` int NULL DEFAULT 0,
  `coupon` int NULL DEFAULT 0,
  `point` int NULL DEFAULT 0,
  `waybill_number` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `fee_delivery` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `fee_additional_shipping` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `note` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `payment_id` int NULL DEFAULT NULL,
  `payment_account_id` int NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `deliveried_at` datetime NULL DEFAULT NULL,
  `payment_confirmed_at` datetime NULL DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `rrt_order_user_id`(`user_id` ASC) USING BTREE,
  INDEX `rrt_order_payment_id`(`payment_id` ASC) USING BTREE,
  CONSTRAINT `rrt_order_payment_id` FOREIGN KEY (`payment_id`) REFERENCES `rrt_order_payment` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `rrt_order_user_id` FOREIGN KEY (`user_id`) REFERENCES `rrt_users` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 148 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

