-- ----------------------------
-- Table structure for rrt_order_items
-- ----------------------------
DROP TABLE IF EXISTS `rrt_order_items`;
CREATE TABLE `rrt_order_items`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `order_id` int NULL DEFAULT NULL,
  `track_id` int NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `contract_track_id` int NULL DEFAULT NULL,
  `price` float NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `rrt_order_items_order_id`(`order_id` ASC) USING BTREE,
  INDEX `rrt_order_items_track_id`(`track_id` ASC) USING BTREE,
  INDEX `rrt_order_items_user_id`(`user_id` ASC) USING BTREE,
  INDEX `rrt_order_items_contract_track`(`contract_track_id` ASC) USING BTREE,
  CONSTRAINT `rrt_order_items_contract_track` FOREIGN KEY (`contract_track_id`) REFERENCES `rrt_contracts_tracks` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `rrt_order_items_order_id` FOREIGN KEY (`order_id`) REFERENCES `rrt_order` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `rrt_order_items_track_id` FOREIGN KEY (`track_id`) REFERENCES `rrt_tracks` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `rrt_order_items_user_id` FOREIGN KEY (`user_id`) REFERENCES `rrt_users` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 153 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

