-- ----------------------------
-- Table structure for rrt_page_translations
-- ----------------------------
DROP TABLE IF EXISTS `rrt_page_translations`;
CREATE TABLE `rrt_page_translations`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `page_id` int NOT NULL,
  `language` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `rrt_page_translations_page_id_language_unique`(`page_id` ASC, `language` ASC) USING BTREE,
  CONSTRAINT `rrt_page_translations_page_id_foreign` FOREIGN KEY (`page_id`) REFERENCES `rrt_pages` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

-- ----------------------------
-- Records of rrt_page_translations
-- ----------------------------
BEGIN;
INSERT INTO `rrt_page_translations` (`id`, `page_id`, `language`, `name`, `content`, `created_at`, `updated_at`) VALUES (1, 16, 'kr', '라이센스 제공', '<p>라이센스 제공</p>', '2025-04-19 02:48:36', '2025-04-19 02:48:36'), (2, 15, 'kr', '환불/반품 정책', '<p>반품 및 환불 정책 &ndash; 1N2 Music<br />\r\n1. 디지털 상품<br />\r\n비트, 악기, 디지털 배포 서비스를 포함하여 1N2Music.com에서 제공되는 모든 상품은 디지털 상품으로 분류됩니다. 디지털 상품의 특성상, 상품을 다운로드하거나 이용하시면 모든 판매는 최종적으로 완료됩니다.</p>\r\n\r\n<p>디지털 콘텐츠 구매 완료에 대해서는 환불해 드리지 않습니다.</p>\r\n\r\n<p>2. 예외 사항<br />\r\n다음과 같은 예외적인 상황에서는 환불이 가능합니다.</p>\r\n\r\n<p>구매하신 파일에 접근하거나 다운로드할 수 없는 경우.</p>\r\n\r\n<p>파일이 손상되었거나 제품 설명과 크게 다른 경우.</p>\r\n\r\n<p>이러한 문제가 발생하는 경우, 구매 후 7일 이내에 저희에게 연락해 주세요. 저희 팀에서 문제를 조사하여 저희의 오류로 판명될 경우, 제품을 재배송하거나 전액 또는 부분 환불해 드립니다.</p>', '2025-04-19 02:52:40', '2025-04-19 02:52:40');
COMMIT;

-- ----------------------------
-- Table structure for rrt_pages
-- ----------------------------
DROP TABLE IF EXISTS `rrt_pages`;
CREATE TABLE `rrt_pages`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `content` longtext CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime NULL DEFAULT NULL,
  `slug` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `image` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `type` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT 'page',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 17 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

-- ----------------------------
-- Records of rrt_pages
-- ----------------------------
BEGIN;
INSERT INTO `rrt_pages` (`id`, `name`, `description`, `content`, `created_at`, `updated_at`, `slug`, `image`, `deleted_at`, `type`) VALUES (5, 'About Us', '_', '<p><img alt=\"\" src=\"https://1n2music.com/public/uploads/ckeditor/pg1-1_1744267594.PNG\" style=\"height:1678px; width:966px\" /></p>', '2025-04-10 14:08:08', NULL, 'about-us', NULL, NULL, 'page'), (6, 'Frequently Asked Questions', 'How to use 1N2 Music Properly!', '<p><strong>How do we sell music on 1N2 Music.com?</strong></p>', '2024-06-03 10:01:07', NULL, 'frequently-asked-questions', NULL, '2025-02-09 11:19:06', 'page'), (7, 'Start Selling', 'Sell Intrumentals and Sound Kits on 1N2 Music', '<p>asdf</p>', '2024-06-03 10:03:33', NULL, 'start-selling', NULL, '2025-02-09 11:21:05', 'page'), (9, 'Contact Us', 'Contact for Support', '<p>Contact Us for Supprt at <strong>Help@1n2music.com</strong></p>', '2025-03-24 05:28:07', NULL, 'contact-us', NULL, NULL, 'page'), (10, 'test', '125', '<p>215</p>', '2025-03-24 05:52:20', NULL, 'test', NULL, '2025-03-24 05:52:40', 'page'), (11, 'Terms of Service', 'Terms of Service', '<p>&nbsp;Terms of Service&nbsp;</p>', '2025-03-24 05:56:31', NULL, 'term-of-service', NULL, NULL, 'term'), (12, 'Privacy Policy', 'Privacy Policy', '<p>Privacy Policy</p>', '2025-03-24 05:56:48', NULL, 'privacy-policy', NULL, NULL, 'term'), (13, '_', '_', '<p><img alt=\"\" src=\"https://1n2music.com/public/uploads/ckeditor/1n2-music-agency_1744293666.png\" style=\"height:125px; width:550px\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://1n2music.com/public/uploads/ckeditor/artists_1744293695.png\" style=\"height:107px; width:966px\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>With over a decade of experience in the entertainment industry, 1N2Music Agency has proudly booked and collaborated with a wide range of artists for events both domestically and internationally. From intimate showcases to large-scale concerts, our team has consistently delivered exceptional results tailored to our clients&rsquo; visions. We take pride in our professionalism, reliability, and dedication to creating memorable live experiences.Whether you&#39;re planning a corporate event, festival, private party, fan meeting or international tour, we are committed to connecting you with the right talent to make your event a success. We look forward to working with you. Please take a moment to fill out our Inquiry form and a member of our team will get back to you promptly to discuss the next steps.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://1n2music.com/public/uploads/ckeditor/process_1744293765.png\" style=\"height:600px; width:855px\" /></p>\r\n\r\n<p><br />\r\n<br />\r\n<a href=\"https://docs.google.com/forms/d/e/1FAIpQLSd6Yqu-bJglYfywVT7_J_4xYGXrzrI-sSI2aqjAmmgzPdOMBg/viewform?usp=dialog\">Inquiry Form (Click here to Fill out the Form)</a></p>', '2025-04-10 14:06:31', NULL, 'agency', 'Logo PNG-p5fMsYtz8R.png', NULL, 'page'), (14, 'Return Policy', 'Return Policy', 'Content policy is here', '2025-04-10 23:05:14', NULL, NULL, NULL, NULL, 'policy'), (15, 'Refund/Return Policy', 'Refund/Return Policy', '<h2>Return &amp; Refund Policy &ndash; 1N2 Music</h2>\r\n\r\n<h3>1. Digital Products</h3>\r\n\r\n<p>All products available on 1N2Music.com, including beats, instrumentals, and digital distribution services, are classified as <strong>digital goods</strong>. Due to the nature of digital products, <strong>all sales are final</strong> once the product has been downloaded or accessed.</p>\r\n\r\n<p>We do not offer refunds for any completed purchases of digital content.</p>\r\n\r\n<h3>2. Exceptions</h3>\r\n\r\n<p>Refunds may be considered under the following exceptional circumstances:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>You are unable to access or download your purchased file(s).</p>\r\n	</li>\r\n	<li>\r\n	<p>The file is corrupted or significantly different from the product description.</p>\r\n	</li>\r\n</ul>\r\n\r\n<p>If you encounter any of these issues, please contact us within <strong>7 days</strong> of your purchase. Our team will investigate the issue, and if it is confirmed to be our error, we will either resend the product or issue a full or partial refund.</p>', '2025-04-19 02:52:40', NULL, 'refundreturn-policy', NULL, NULL, 'shop-policy'), (16, 'License offers', 'License offers', '<p>License offers&nbsp;</p>', '2025-04-19 02:48:36', NULL, 'license-offers', NULL, NULL, 'shop-policy');
COMMIT;

-- ----------------------------
-- Table structure for rrt_payment_accounts
-- ----------------------------
DROP TABLE IF EXISTS `rrt_payment_accounts`;
CREATE TABLE `rrt_payment_accounts`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `email` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `first_name` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `last_name` varchar(2562) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `country` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `address_1` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `address_2` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `commision` float NULL DEFAULT NULL,
  `city` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `postal_code` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT current_timestamp(),
  `updated_at` datetime NULL DEFAULT current_timestamp(),
  `account_type` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `date_of_birth` date NULL DEFAULT NULL,
  `province` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `unit` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `company_name` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `phone` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `tax_id` int NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE,
  INDEX `tax_id`(`tax_id` ASC) USING BTREE,
  CONSTRAINT `fk_tax_type` FOREIGN KEY (`tax_id`) REFERENCES `rrt_tax_type` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `fk_user` FOREIGN KEY (`user_id`) REFERENCES `rrt_users` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 131 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

-- ----------------------------
-- Records of rrt_payment_accounts
