INSERT INTO `rrt_plans` (`id`, `name`, `type`, `description`, `commission`, `is_free`, `pricing_monthly`, `pricing_annually`, `content`, `slug`, `default_signup`, `created_at`, `updated_at`, `order_number`) VALUES (1, 'Free', 'seller', 'For sellers just starting their music business or those who want to give the BeatNara platform a try\r\n                        ', NULL, 1, 0, 0, '<ul class=\"list-none\">\r\n<li>Up to 10 Tracks</li>\r\n<li>Upload Track Stems</li>\r\n<li>Instant Payments</li>\r\n<li>Accept PayPal Payments</li>\r\n<li>Accept Stripe Payments</li>\r\n</ul>', 'free', 0, '2023-07-10 15:02:32', NULL, 0), (2, 'Basic Seller', 'seller', 'For sellers who want to grow their business and access advanced features', NULL, 0, 9.99, 7.99, '<ul class=\"list-none\">\r\n<li>Unlimited Tracks</li>\r\n<li>20 Monthly Private Messages</li>\r\n<li>Sell Sound Kits</li>\r\n<li>Sell Custom Services</li>\r\n</ul>', 'basic', 0, '2023-07-10 15:03:42', NULL, 1), (3, 'Pro Seller', 'seller', 'For sellers who want to scale their business quickly with a custom web store', 0.8, 0, 5, 50, '<ul class=\"list-none\">\r\n<li>100% of Pro Page Sales Revenue</li>\r\n<li>Unlimited Monthly Private Messages</li>\r\n<li>Unlimited Number of License Agreements</li>\r\n<li>2 Submissions per Opportunity</li>\r\n</ul>', 'pro', 1, '2023-07-10 15:04:44', NULL, 2);
