-- ----------------------------
-- Table structure for rrt_recognitions
-- ----------------------------
DROP TABLE IF EXISTS `rrt_recognitions`;
CREATE TABLE `rrt_recognitions`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `artist` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `title` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `album` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `release_date` date NULL DEFAULT NULL,
  `label` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `timecode` time NULL DEFAULT NULL,
  `song_link` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `musicbrainz` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `apple_music` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `spotify` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `deezer` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `napster` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE CURRENT_TIMESTAMP,
  `platforms` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 66 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

-- ----------------------------
-- Records of rrt_recognitions
