-- ----------------------------
-- Table structure for rrt_request_payouts
-- ----------------------------
DROP TABLE IF EXISTS `rrt_request_payouts`;
CREATE TABLE `rrt_request_payouts`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NULL DEFAULT NULL,
  `status` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  `manager` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `seller` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `owner` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `method_payment` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `tax_type` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `withdrawal_method` int NULL DEFAULT NULL,
  `amount_tax` double NULL DEFAULT NULL,
  `note` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `amount_supply` float NULL DEFAULT NULL,
  `vat` float NULL DEFAULT NULL,
  `amount_request` float NULL DEFAULT NULL,
  `amount_report` float NULL DEFAULT NULL,
  `memo` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `amount_payment` float NULL DEFAULT NULL,
  `transaction_id` int NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `rrt_request_payouts_user_id`(`user_id` ASC) USING BTREE,
  INDEX `rrt_transaction_id`(`transaction_id` ASC) USING BTREE,
  INDEX `withdrawal_method`(`withdrawal_method` ASC) USING BTREE,
  CONSTRAINT `fk_method_user` FOREIGN KEY (`withdrawal_method`) REFERENCES `rrt_payout_method` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `rrt_request_payouts_user_id` FOREIGN KEY (`user_id`) REFERENCES `rrt_users` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `rrt_transaction_id` FOREIGN KEY (`transaction_id`) REFERENCES `rrt_transactions` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 27 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

