-- ----------------------------
-- Table structure for rrt_subscription_orders
-- ----------------------------
DROP TABLE IF EXISTS `rrt_subscription_orders`;
CREATE TABLE `rrt_subscription_orders`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `subscription_id` int NULL DEFAULT NULL,
  `cycle` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `total` float NULL DEFAULT NULL,
  `status` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT current_timestamp(),
  `updated_at` datetime NULL DEFAULT current_timestamp(),
  `deleted_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `subscription_orders_subscription_id`(`subscription_id` ASC) USING BTREE,
  INDEX `subscription_orders_user_id`(`user_id` ASC) USING BTREE,
  CONSTRAINT `subscription_orders_subscription_id` FOREIGN KEY (`subscription_id`) REFERENCES `rrt_subscriptions` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `subscription_orders_user_id` FOREIGN KEY (`user_id`) REFERENCES `rrt_users` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 271 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

