-- ----------------------------
-- Table structure for rrt_subscriptions
-- ----------------------------
DROP TABLE IF EXISTS `rrt_subscriptions`;
CREATE TABLE `rrt_subscriptions`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `slug` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `type` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `price` float NULL DEFAULT 0,
  `pricing_annually` float NOT NULL DEFAULT 0,
  `max_track` int NULL DEFAULT NULL,
  `commission` float NULL DEFAULT NULL,
  `heading` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `content` longtext CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  `agreement_url` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `background` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  `description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

-- ----------------------------
-- Records of rrt_subscriptions
-- ----------------------------
BEGIN;
INSERT INTO `rrt_subscriptions` (`id`, `name`, `slug`, `type`, `price`, `pricing_annually`, `max_track`, `commission`, `heading`, `content`, `agreement_url`, `background`, `created_at`, `updated_at`, `description`) VALUES (1, 'Publishing', 'publishing', 'subcriber', 0, 1000, NULL, NULL, 'Today\'s the day you start collecting your royalties', '<ul>\r\n<li>Protect your music</li>\r\n                       \r\n                        <li>Direct payment</li>\r\n                        <li> One-year contracts</li>\r\n                        <li> Worldwide royalty collection</li>\r\n                        <li>Keep 100% ownership </li>\r\n                    </ul>', '#', 'public/images/publishing-landing-page.jpg', '2023-07-11 00:02:51', NULL, NULL), (2, 'Digital Distribution', 'distribution', 'subcriber', 0, 100, NULL, NULL, 'Let the world hear your voice', '<ul>\r\n                        <li>Put your music on Melon, Genie Music, Spotify, Apple Music, TikTok and 30+ stores </li>\r\n                        <li>Add collaborators and split revenue</li>\r\n                        <li> Upload an unlimited number of tracks\' as a seperate option on the table of contents</li>\r\n                    </ul>', '#', 'public/images/beat-id-landing-page.png', '2023-07-11 00:02:51', NULL, NULL), (3, 'Basic Seller', 'basic', 'seller', 0, 0, 5, 0.7, 'Let the world hear your voice', '<p>Sell your Instrumentals and make revenue</p>', '#', 'public/images/beat-id-landing-page.png', '2023-07-11 00:02:51', NULL, NULL);
