-- ----------------------------
-- Table structure for rrt_tracks_collaborators
-- ----------------------------
DROP TABLE IF EXISTS `rrt_tracks_collaborators`;
CREATE TABLE `rrt_tracks_collaborators`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NULL DEFAULT NULL,
  `profit_share` int NULL DEFAULT NULL,
  `publishing` int NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

-- ----------------------------
-- Records of rrt_tracks_collaborators
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for rrt_tracks_files
-- ----------------------------
DROP TABLE IF EXISTS `rrt_tracks_files`;
CREATE TABLE `rrt_tracks_files`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `track_id` int NULL DEFAULT NULL,
  `user_id` int NULL DEFAULT NULL,
  `name` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `type` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `tf_track_id`(`track_id` ASC) USING BTREE,
  INDEX `tf_user_id`(`user_id` ASC) USING BTREE,
  CONSTRAINT `tf_track_id` FOREIGN KEY (`track_id`) REFERENCES `rrt_tracks` (`id`) ON DELETE SET NULL ON UPDATE SET NULL,
  CONSTRAINT `tf_user_id` FOREIGN KEY (`user_id`) REFERENCES `rrt_users` (`id`) ON DELETE SET NULL ON UPDATE SET NULL
) ENGINE = InnoDB AUTO_INCREMENT = 190 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci;

